BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?prop ?value ?valueName WHERE {
  ?pkg vocab:NamedElement_name "Work Packages" .
  ?pkg ?prop ?value .
  OPTIONAL { ?value vocab:NamedElement_name ?valueName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?elem ?name ?type WHERE {
  BIND(<http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages> AS ?pkg)
  ?pkg vocab:Element_ownedElement ?elem .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
  ?elem rdf:type ?type .
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?elem ?name ?type WHERE {
  ?pkg vocab:NamedElement_name "WorkPackages" .
  ?pkg vocab:Namespace_ownedMember ?elem .
  OPTIONAL { ?elem vocab:NamedElement_name ?name }
  ?elem rdf:type ?type .
}
